#include<bits/stdc++.h>
using namespace std;
int m, n;
bool flag=0;
long long flip(long long x) { //翻转整型数字
	long long y = 0;
	while (x) {
		y += x % 10;
		x /= 10;
		y *= 10;
	}
	y /= 10;
	return y;
}
bool prime_number(long long x) { //判断质数
	for (int i = 2; i * i <= x; i++) if (x % i == 0) return false;
	return true;
}
int main() {
	cin >> m >> n;
	for (int i = m; i <= n; i++) {
		if (prime_number(i)) {
			if (prime_number(flip(i))) {

				if(flag) cout<<",";
                cout << i;
				flag=1;
			}
		}
	}
    if(!flag) cout<<"No";
	return 0;
}
